#include <iostream>
#include <string>
#include <vector>
#include <memory>

// Base class
class Enemy {
protected:
    std::string name;
    int health;
    int attackPower;

public:
    Enemy(std::string n, int h, int a) : name(n), health(h), attackPower(a) {}

    virtual ~Enemy() {}

    // Pure virtual function — makes this an abstract class
    virtual void attack(Enemy& target) = 0;

    virtual void takeDamage(int damage) {
        health -= damage;
        if (health < 0) health = 0;
        std::cout << name << " took " << damage << " damage! (" << health << " HP left)" << std::endl;
    }

    virtual void display() const {
        std::cout << name << " (HP: " << health << ", ATK: " << attackPower << ")" << std::endl;
    }

    bool isAlive() const { return health > 0; }
    std::string getName() const { return name; }
};

// Derived classes
class Goblin : public Enemy {
public:
    Goblin(std::string n, int h, int a) : Enemy(n, h, a) {}

    void attack(Enemy& target) override {
        int damage = attackPower + (rand() % 5);
        std::cout << name << " stabs with a dagger for " << damage << " damage!" << std::endl;
        target.takeDamage(damage);
    }
};

class Orc : public Enemy {
public:
    Orc(std::string n, int h, int a) : Enemy(n, h, a) {}

    void attack(Enemy& target) override {
        int damage = attackPower + (rand() % 8) + 5;
        std::cout << name << " swings an axe for " << damage << " damage!" << std::endl;
        target.takeDamage(damage);
    }
};

class Skeleton : public Enemy {
public:
    Skeleton(std::string n, int h, int a) : Enemy(n, h, a) {}

    void attack(Enemy& target) override {
        int damage = attackPower + (rand() % 10);
        std::cout << name << " shoots a bone arrow for " << damage << " damage!" << std::endl;
        target.takeDamage(damage);
    }

    void takeDamage(int damage) override {
        // Skeletons take reduced damage
        damage = damage / 2;
        Enemy::takeDamage(damage);
        std::cout << " (Skeleton's bones reduce damage!)" << std::endl;
    }
};

class Boss : public Enemy {
private:
    std::string specialMove;

public:
    Boss(std::string n, int h, int a, std::string move) : Enemy(n, h, a), specialMove(move) {}

    void attack(Enemy& target) override {
        int damage = attackPower + (rand() % 15) + 10;
        std::cout << name << " uses " << specialMove << " for " << damage << " damage!" << std::endl;
        target.takeDamage(damage);

        // Boss special: sometimes attack again
        if (rand() % 3 == 0) {
            std::cout << name << " attacks again!" << std::endl;
            target.takeDamage(damage / 2);
        }
    }

    void display() const override {
        Enemy::display();
        std::cout << "  Special: " << specialMove << std::endl;
    }
};

// Polymorphic function
void battleRound(Enemy& attacker, Enemy& defender) {
    std::cout << "\n=== Battle Round ===" << std::endl;
    std::cout << attacker.getName() << " attacks " << defender.getName() << "!" << std::endl;
    attacker.attack(defender);

    if (!defender.isAlive()) {
        std::cout << defender.getName() << " has been defeated!" << std::endl;
    }
}

int main() {
    std::srand(std::time(0));

    std::cout << "=== Polymorphism in Action ===" << std::endl;

    // Create different enemies
    Goblin goblin("Goblin", 30, 8);
    Orc orc("Orc", 50, 12);
    Skeleton skeleton("Skeleton", 40, 10);
    Boss boss("Dragon", 100, 20, "Flame Breath");

    std::cout << "\n=== Enemy Roster ===" << std::endl;
    goblin.display();
    orc.display();
    skeleton.display();
    boss.display();

    std::cout << "\n=== Polymorphic Battle ===" << std::endl;

    // All enemies in a vector (polymorphism!)
    std::vector<Enemy*> enemies = {&goblin, &orc, &skeleton, &boss};

    // Each enemy attacks the next one
    for (size_t i = 0; i < enemies.size(); i++) {
        size_t next = (i + 1) % enemies.size();
        if (enemies[i]->isAlive() && enemies[next]->isAlive()) {
            battleRound(*enemies[i], *enemies[next]);
        }
    }

    std::cout << "\n=== Final Status ===" << std::endl;
    for (Enemy* e : enemies) {
        e->display();
    }

    // Polymorphism with smart pointers
    std::cout << "\n=== Smart Pointer Polymorphism ===" << std::endl;
    std::vector<std::unique_ptr<Enemy>> enemyPtrs;
    enemyPtrs.push_back(std::make_unique<Goblin>("Goblin2", 25, 7));
    enemyPtrs.push_back(std::make_unique<Orc>("Orc2", 45, 11));

    for (auto& e : enemyPtrs) {
        e->display();
    }

    return 0;
}

